      updateRatingVisual(selectedRating);

      if (finalSubmitBtn) {
        finalSubmitBtn.removeAttribute('disabled');
      }
    });

    btn.addEventListener('mouseenter', () => {
      const val = parseInt(btn.getAttribute('data-value'), 10);
      updateRatingVisual(val);
    });

    btn.addEventListener('mouseleave', () => {
      updateRatingVisual(selectedRating);
    });
  });
}

// Submit Final Match Button (Step 4)
if (finalSubmitBtn) {
  finalSubmitBtn.addEventListener('click', () => {
    if (selectedRating === 0) {
      alert("Please select a rating!");
      return;
    }

    // Dynamic matching logic
    let matchId = '';
    if (selectedFocus === 'status') {
      if (selectedStep3 === 'peer') {
        matchId = 'aisha';
      } else {
        if (selectedStep2 === 'family') {
          matchId = 'david_chee';
        } else if (selectedStep2 === 'greencard') {
          matchId = 'hassan';
        } else {
          matchId = 'sarah';
        }
      }
    } else if (selectedFocus === 'career') {
      if (selectedStep2 === 'hired') {
        matchId = 'david';
      } else {
        matchId = 'michael';
      }
    } else if (selectedFocus === 'finance') {
      matchId = 'amanda';
    }

    if (matchId) {
      const dirLink = document.querySelector('.nav-link[data-target="directory"]');
