function updateRatingVisual(val) {
  if (activePath) {
    // Line total stroke-dasharray is 210px
    const offset = val === 0 ? 210 : 210 * (1 - val / 10);
    activePath.style.strokeDashoffset = offset;
  }

  if (traveler) {
    const t = val === 0 ? 0 : (val - 1) / 9;
    const coords = getPathCoordinate(t);
    traveler.style.transform = `translate(${coords.x}px, ${coords.y}px)`;
  }

  if (sun) {
    const lift = val === 0 ? 0 : (val / 10) * 70;
    sun.style.transform = `translateY(${-lift}px)`;
  }

  if (sunGlow) {
    const lift = val === 0 ? 0 : (val / 10) * 70;
    sunGlow.style.transform = `translateY(${-lift}px)`;
    sunGlow.style.opacity = val === 0 ? 0 : (val / 10) * 0.9;
  }

  if (skyGlowStop) {
    const color = val === 0 ? '#eae2d5' : skyColors[val - 1];
    skyGlowStop.setAttribute('stop-color', color);
  }

  if (statusText) {
    if (val === 0) {
      statusText.innerText = "Select a number to rate your current progress.";
    } else {
      const categoryDesc = statusDescriptions[selectedFocus];
      statusText.innerText = categoryDesc ? categoryDesc[val] : "Select a number to rate your current progress.";
    }
  }
}

