// Goal step navigator
function goToGoalStep(index) {
  currentGoalStepIndex = index;
  const category = goalStepsToAsk[index];

  const allSlides = quizCard.querySelectorAll('.quiz-step-slide');
  allSlides.forEach(s => {
    s.style.display = 'none';
    s.classList.remove('active');
  });

  const slide = quizCard.querySelector(`.quiz-step-slide[data-step="goal-${category}"]`);
  if (slide) {
    slide.style.display = 'block';
    setTimeout(() => slide.classList.add('active'), 10);
  }

  // Update Title text dynamically with the current rating
  if (category === 'status') {
    const title = document.getElementById('title-goal-status');
    if (title) title.innerHTML = `What would it take to move your <strong>Status & Visas</strong> from <strong>${ratings.status}</strong> to 10?`;
  } else if (category === 'career') {
    const title = document.getElementById('title-goal-career');
    if (title) title.innerHTML = `What would it take to move your <strong>Career & Jobs</strong> from <strong>${ratings.career}</strong> closer to 10?`;
  } else if (category === 'finance') {
    const title = document.getElementById('title-goal-finance');
    if (title) title.innerHTML = `What would it take to move your <strong>Finance & Credit</strong> from <strong>${ratings.finance}</strong> closer to 10?`;
  }

  // SVG path active highlights: fade out inactive curves to 0.15
  const paths = {
    status: document.getElementById('horizon-active-status'),
    career: document.getElementById('horizon-active-career'),
    finance: document.getElementById('horizon-active-finance')
  };
  const travelers = {
    status: document.getElementById('horizon-traveler-status'),
    career: document.getElementById('horizon-traveler-career'),
    finance: document.getElementById('horizon-traveler-finance')
  };

  Object.keys(paths).forEach(key => {
    const path = paths[key];
    const trav = travelers[key];
    if (key === category) {
      if (path) path.style.opacity = '1';
      if (trav) trav.style.opacity = '1';
    } else {
      if (path) path.style.opacity = '0.15';
      if (trav) trav.style.opacity = '0.15';
    }
  });

  if (progressFill) progressFill.style.width = '100%';
  if (stepLabel) {
    const humanIndex = index + 1;
    stepLabel.innerText = `Goal ${humanIndex} of ${goalStepsToAsk.length}`;
  }

  const sharedVisualizer = quizCard.querySelector('.shared-horizon-visualizer');
  if (sharedVisualizer) sharedVisualizer.style.display = 'flex';
}

