    quizCard.querySelectorAll('.goal-checkbox-input').forEach(i => i.checked = false);
    if (ratingBtns) ratingBtns.forEach(b => b.classList.remove('active'));

    restorePathOpacities();
    updateHorizonVisuals();
    goToStep(1);
  }
}

