// Dynamically populate Results View
function renderResultsPage() {
  // 1. Update Scores Dashboard
  const valStatus = ratings.status || 0;
  const valCareer = ratings.career || 0;
  const valFinance = ratings.finance || 0;

  // Category Label Names based on selectedFocus
  const focusConfig = quizContentConfig[selectedFocus || 'status'];
  const catNames = (focusConfig && focusConfig.categories) ? focusConfig.categories : ['Visa & Status', 'Career & Jobs', 'Finance & Credit'];

  // Score color helper
  const scoreColor = (v) => v >= 8 ? '#10b981' : v >= 5 ? '#d97706' : '#c85a5a';
  const scoreEmoji = (v) => v >= 8 ? '🟢' : v >= 5 ? '🟡' : '🔴';
  const scoreLabel = (v) => v >= 8 ? 'Strong' : v >= 5 ? 'Developing' : 'Needs Work';

  // Update score boxes with color coding
  const scoreBoxes = [
    { id: 'results-score-status', lbl: 'results-lbl-status', val: valStatus },
    { id: 'results-score-career', lbl: 'results-lbl-career', val: valCareer },
    { id: 'results-score-finance', lbl: 'results-lbl-finance', val: valFinance }
  ];

  scoreBoxes.forEach((s, i) => {
    const scoreEl = document.getElementById(s.id);
    const lblEl = document.getElementById(s.lbl);
    if (scoreEl) {
      scoreEl.innerText = `${s.val}/10`;
      scoreEl.style.color = scoreColor(s.val);
    }
    if (lblEl) lblEl.innerText = catNames[i];

    // Inject progress bar + status badge into parent .score-item-box
    const box = scoreEl ? scoreEl.closest('.score-item-box') : null;
    if (box) {
      box.style.borderColor = scoreColor(s.val) + '33';
      // Add bar + badge if not already there
      if (!box.querySelector('.score-bar-track')) {
        const bar = document.createElement('div');
        bar.className = 'score-bar-track';
        bar.style.cssText = `height:5px; background: var(--border-color); border-radius:10px; margin-top:8px; overflow:hidden;`;
        const fill = document.createElement('div');
        fill.className = 'score-bar-fill';
        fill.style.cssText = `height:100%; width:${s.val * 10}%; background:${scoreColor(s.val)}; border-radius:10px; transition: width 1s cubic-bezier(0.16,1,0.3,1);`;
        bar.appendChild(fill);
        box.appendChild(bar);

        const badge = document.createElement('span');
        badge.style.cssText = `font-size:0.7rem; font-weight:700; color:${scoreColor(s.val)}; margin-top:4px; display:block;`;
        badge.innerText = `${scoreEmoji(s.val)} ${scoreLabel(s.val)}`;
        box.appendChild(badge);
      } else {
        // Update existing bar width
        const fill = box.querySelector('.score-bar-fill');
        if (fill) { fill.style.width = `${s.val * 10}%`; fill.style.background = scoreColor(s.val); }
        const badge = box.querySelector('span[style*="0.7rem"]');
        if (badge) { badge.style.color = scoreColor(s.val); badge.innerText = `${scoreEmoji(s.val)} ${scoreLabel(s.val)}`; }
      }
    }
  });

  // 2. Identify biggest bottleneck (only among scored categories)
  let bottleneck = 'status';
  let lowestScore = valStatus > 0 ? valStatus : 10;
  if (valCareer > 0 && valCareer < lowestScore) { lowestScore = valCareer; bottleneck = 'career'; }
  if (valFinance > 0 && valFinance < lowestScore) { lowestScore = valFinance; bottleneck = 'finance'; }

  const bottleneckIdx = bottleneck === 'status' ? 0 : bottleneck === 'career' ? 1 : 2;
  const bottleneckName = catNames[bottleneckIdx];

  const bottleneckEl = document.getElementById('results-bottleneck-name');
  if (bottleneckEl) bottleneckEl.innerText = bottleneckName;

  const lookupFocus = selectedFocus || 'status';
  const bottleneckDesc = (statusDescriptions[lookupFocus] && statusDescriptions[lookupFocus][lowestScore])
    ? statusDescriptions[lookupFocus][lowestScore]
    : `Your ${bottleneckName} score of ${lowestScore}/10 is your biggest opportunity for growth. Your matched advisor will build a prioritized action plan to move this score forward.`;

  const bottleneckDescEl = document.getElementById('results-bottleneck-desc');
  if (bottleneckDescEl) bottleneckDescEl.innerText = bottleneckDesc;

  // Color the bottleneck banner dynamically
  const bottleneckCard = document.getElementById('results-bottleneck-card');
  if (bottleneckCard) {
    const bc = scoreColor(lowestScore);
    bottleneckCard.style.background = bc + '12';
    bottleneckCard.style.borderColor = bc + '40';
    const h4 = bottleneckCard.querySelector('h4');
    const p = bottleneckCard.querySelector('p');
    if (h4) h4.style.color = bc;
    if (p) p.style.color = bc;
  }

  // 3. Render Selected Goals action items list
  const goalsContainer = document.getElementById('results-goals-list');
  if (goalsContainer) {
    goalsContainer.innerHTML = '';
    const goals = (selectedStep9 && selectedStep9.length > 0) ? selectedStep9 : [];

    if (goals.length > 0) {
      goals.forEach((val, idx) => {
        const expl = goalExplanations[val] || { title: val, desc: 'Your matched advisor will define a concrete roadmap for this priority.' };
        const goalEl = document.createElement('div');
        goalEl.className = 'results-goal-item';
        goalEl.style.cssText = `display:flex; gap:14px; align-items:flex-start; padding:14px 16px; background:var(--bg-primary); border:1px solid var(--border-color); border-radius:12px; animation: fadeInUp 0.4s ease both; animation-delay:${idx * 80}ms;`;
        goalEl.innerHTML = `
          <div style="width:36px; height:36px; border-radius:10px; background:var(--accent-light); display:flex; align-items:center; justify-content:center; flex-shrink:0; font-size:1rem;">🎯</div>
          <div style="flex:1;">
            <span style="font-size:0.9rem; font-weight:700; color:var(--text-primary); display:block; margin-bottom:4px;">${expl.title}</span>
            <span style="font-size:0.8rem; color:var(--text-secondary); line-height:1.45;">${expl.desc}</span>
          </div>
          <span style="font-size:0.72rem; font-weight:700; color:var(--accent); background:var(--accent-light); padding:3px 8px; border-radius:20px; white-space:nowrap; align-self:flex-start;">Priority ${idx + 1}</span>
        `;
        goalsContainer.appendChild(goalEl);
      });
    } else {
      goalsContainer.innerHTML = `
