            </div>
            <input type="email" id="gate-email" placeholder="Email Address" required style="width:100%; padding:12px 14px; background:rgba(255,255,255,0.06); border:1px solid rgba(255,255,255,0.12); border-radius:10px; color:#fff; font-size:0.9rem; box-sizing:border-box; outline:none;">
            <input type="password" id="gate-password" placeholder="Password" required style="width:100%; padding:12px 14px; background:rgba(255,255,255,0.06); border:1px solid rgba(255,255,255,0.12); border-radius:10px; color:#fff; font-size:0.9rem; box-sizing:border-box; outline:none;">
            <div id="gate-error" style="color:#f87171; font-size:0.8rem; display:none;"></div>
            <button type="submit" id="gate-submit-btn" style="width:100%; padding:14px; background:linear-gradient(135deg,#10b981,#059669); color:#fff; border:none; border-radius:12px; font-size:0.95rem; font-weight:700; cursor:pointer; margin-top:4px; letter-spacing:.02em;">Create Account & Unlock Results</button>
