        </div>
      `;

      document.body.appendChild(fullGate);
      window._gateMode = 'signup';

      // Wire gate form submit
      const gateForm = document.getElementById('gate-auth-form');
      if (gateForm) {
        gateForm.addEventListener('submit', (e) => {
          e.preventDefault();
          const submitBtn = document.getElementById('gate-submit-btn');
          const errorEl = document.getElementById('gate-error');
          const fullname = window._gateMode === 'signup' ? (document.getElementById('gate-fullname').value.trim()) : 'User';

          if (window._gateMode === 'signup' && !fullname) {
            errorEl.innerText = 'Please enter your full name.';
            errorEl.style.display = 'block';
            return;
          }

          if (submitBtn) {
            submitBtn.disabled = true;
            submitBtn.innerHTML = '<span style="display:inline-block;width:14px;height:14px;border:2px solid rgba(255,255,255,0.3);border-top-color:#fff;border-radius:50%;animation:spin 0.8s linear infinite;vertical-align:middle;margin-right:8px;"></span> Unlocking your plan...';
          }

          setTimeout(() => {
            isUserLoggedIn = true;
            updateHeaderNavActions(true);

            // Dismiss gate with animation
            fullGate.style.transition = 'opacity 0.5s ease';
            fullGate.style.opacity = '0';
            setTimeout(() => {
              if (fullGate.parentNode) fullGate.parentNode.removeChild(fullGate);
            }, 500);

            // Refresh page state
            renderResultsPage();
            const welcomeBanner = document.getElementById('results-welcome-banner');
            if (welcomeBanner) welcomeBanner.style.display = 'flex';
            const authContainer = document.getElementById('results-auth-container');
            if (authContainer) authContainer.style.display = 'none';
          }, 1200);
        });
      }
    } else {
      fullGate.style.display = 'flex';
      fullGate.style.opacity = '1';
    }

    // Keep existing inline lock overlay visible
    const lockOverlay = document.getElementById('results-lock-overlay');
    if (lockOverlay) lockOverlay.style.display = 'flex';
    const authContainer = document.getElementById('results-auth-container');
    if (authContainer) authContainer.style.display = 'none';
    const welcomeBanner = document.getElementById('results-welcome-banner');
    if (welcomeBanner) welcomeBanner.style.display = 'none';

  } else {
    // Logged in — dismiss gate if present
    if (fullGate) {
      fullGate.style.display = 'none';
    }
    const lockOverlay = document.getElementById('results-lock-overlay');
    if (lockOverlay) lockOverlay.classList.add('hidden');
    const authContainer = document.getElementById('results-auth-container');
    if (authContainer) authContainer.style.display = 'none';
    const welcomeBanner = document.getElementById('results-welcome-banner');
    if (welcomeBanner) welcomeBanner.style.display = 'flex';
    updateHeaderNavActions(true);
  }
}

