const step2 = document.getElementById('timeline-step-2');
const step2Ind = document.getElementById('timeline-step-2-indicator');
const step3 = document.getElementById('timeline-step-3');
const step3Ind = document.getElementById('timeline-step-3-indicator');
const step4 = document.getElementById('timeline-step-4');
const step4Ind = document.getElementById('timeline-step-4-indicator');

let totalTimelinePct = 25; // Phase 1 is done
totalTimelinePct += Math.round(checklistPct * 0.5); // Phase 2 counts up to 50%
if (hasBooking) totalTimelinePct += 15; // Phase 3 booked is 15%
if (checklistPct === 100 && hasBooking) totalTimelinePct += 10; // Phase 4 is 10%

if (timelinePercent) timelinePercent.innerText = `${totalTimelinePct}%`;

// Style Step 2 (Action Prep)
if (checklistPct > 0) {
  if (step2) step2.style.borderColor = 'var(--accent)';
  if (step2Ind) {
    step2Ind.style.background = 'var(--accent)';
    step2Ind.style.color = '#fff';
    step2Ind.innerText = checklistPct === 100 ? '✓' : '2';
  }
} else {
  if (step2) step2.style.borderColor = 'var(--border-color)';
  if (step2Ind) {
    step2Ind.style.background = 'var(--bg-tertiary)';
    step2Ind.style.color = 'var(--text-secondary)';
    step2Ind.innerText = '2';
  }
}

// Style Step 3 (Expert Review)
if (hasBooking) {
  if (step3) step3.style.borderColor = 'var(--accent)';
  if (step3Ind) {
    step3Ind.style.background = 'var(--accent)';
    step3Ind.style.color = '#fff';
    step3Ind.innerText = '✓';
  }
} else {
  if (step3) step3.style.borderColor = 'var(--border-color)';
  if (step3Ind) {
    step3Ind.style.background = 'var(--bg-tertiary)';
    step3Ind.style.color = 'var(--text-secondary)';
    step3Ind.innerText = '3';
  }
}

// Style Step 4 (Landing & Setup)
if (totalTimelinePct === 100) {
  if (step4) step4.style.borderColor = 'var(--accent)';
  if (step4Ind) {
    step4Ind.style.background = 'var(--accent)';
    step4Ind.style.color = '#fff';
    step4Ind.innerText = '✓';
  }
} else {
  if (step4) step4.style.borderColor = 'var(--border-color)';
  if (step4Ind) {
    step4Ind.style.background = 'var(--bg-tertiary)';
    step4Ind.style.color = 'var(--text-secondary)';
    step4Ind.innerText = '4';
  }
}

// 1.0.1 Next Critical Step Hero Card
const nextStepTitle = document.getElementById('overview-next-step-title');
const nextStepDesc = document.getElementById('overview-next-step-desc');
const btnNextStepAction = document.getElementById('btn-overview-next-step-action');

let firstUnchecked = checklistItems.find(item => {
  const val = typeof item === 'object' ? item.val : item;
  return !savedGoals.includes(val);
});

if (firstUnchecked) {
  const label = typeof firstUnchecked === 'object' ? firstUnchecked.label : firstUnchecked;
  const val = typeof firstUnchecked === 'object' ? firstUnchecked.val : firstUnchecked;

  if (nextStepTitle) nextStepTitle.innerText = label;

  let desc = "Relocating requires getting ahead of logistics. Talk with your expert advisor to review templates, legal requirements, or setup details.";
  let actionBtnText = "⚡ Complete Priority";
  let actionFn = () => switchDashboardTab('roadmap');

  if (val === 'visa' || val === 'talent' || val === 'nomad') {
    desc = `Securing legal entry is your highest priority. Check your eligibility rules and compile immigration credentials. Drop questions to your matched expert or upload your passport scans.`;
    actionBtnText = "💬 Ask Advisor About Visa";
    actionFn = () => switchDashboardTab('messages');
  } else if (val === 'translations' || val === 'forms' || val === 'notarize_docs') {
    desc = `Translate and notarize your records (birth certificate, diploma, and background scan). Drop them directly into the Quick-Upload widget below to share with your advisor.`;
    actionBtnText = "📤 Drop Scan in Vault";
    actionFn = () => {
      const zone = document.getElementById('overview-quick-upload-dropzone');
      if (zone) {
        zone.scrollIntoView({ behavior: 'smooth' });
        zone.style.borderColor = 'var(--accent)';
        setTimeout(() => { zone.style.borderColor = 'var(--border-color)'; }, 1000);
      }
    };
  } else if (val === 'cv_format' || val === 'employer_list' || val === 'recruiter_outreach' || val === 'cover_letters') {
    desc = `Expat job markets require specific CV structures. Review the local guidelines in the Career Coach tool or book a resume audit call with Hassan M.`;
    actionBtnText = "📅 Book Resume Coach Call";
    actionFn = () => switchDashboardTab('bookings');
  } else if (val === 'bank_requirements' || val === 'secured_card' || val === 'currency_transfer' || val === 'tax_number') {
    desc = `Setup your tax ID (SSN/TIN equivalent) and open a multi-currency account. Avoid high transfer rates. Check out the Currency Simulator tool in the right panel.`;
    actionBtnText = "💰 View Currency Simulator";
    actionFn = () => {
      const toolCard = document.getElementById('overview-custom-tool-card');
      if (toolCard) {
        toolCard.scrollIntoView({ behavior: 'smooth' });
      }
    };
  }

  if (nextStepDesc) nextStepDesc.innerText = desc;
  if (btnNextStepAction) {
    btnNextStepAction.innerText = actionBtnText;
    btnNextStepAction.onclick = actionFn;
  }
} else {
  if (nextStepTitle) nextStepTitle.innerText = "All priorities completed!";
  if (nextStepDesc) nextStepDesc.innerText = "Excellent job! You are relocation-ready. Set up your travel itinerary and do a final wrap-up check with your advisor.";
  if (btnNextStepAction) {
    btnNextStepAction.innerText = "💬 Open Wrap-Up Chat";
    btnNextStepAction.onclick = () => switchDashboardTab('messages');
  }
}

// 1.0.2 Scores Card
const overviewScoreStatus = document.getElementById('overview-score-status');
const overviewScoreCareer = document.getElementById('overview-score-career');
const overviewScoreFinance = document.getElementById('overview-score-finance');
if (overviewScoreStatus) overviewScoreStatus.innerText = `${quizResults.scores?.status || 0}/10`;
if (overviewScoreCareer) overviewScoreCareer.innerText = `${quizResults.scores?.career || 0}/10`;
if (overviewScoreFinance) overviewScoreFinance.innerText = `${quizResults.scores?.finance || 0}/10`;

const bottleneckAlert = document.getElementById('overview-bottleneck-alert');
const bottleneckTxt = document.getElementById('overview-bottleneck-txt');
if (bottleneckTxt) {
  const bottleneckName = (focusArea === 'Status & Visas') ? 'Immigration Status' : (focusArea === 'Career & Jobs' ? 'Job Placement' : 'Financial Setup');
  bottleneckTxt.innerText = bottleneckName;
}

// 1.0.3 Matched Advisor (Overview Card)
const advisor = mockAdvisorsData[focusArea] || mockAdvisorsData['Status & Visas'];
const overAdvisorAvatar = document.getElementById('overview-advisor-avatar');
const overAdvisorName = document.getElementById('overview-advisor-name');
const overAdvisorRole = document.getElementById('overview-advisor-role');
if (overAdvisorAvatar) overAdvisorAvatar.src = advisor.avatar;
if (overAdvisorName) overAdvisorName.innerText = advisor.name;
if (overAdvisorRole) overAdvisorRole.innerText = advisor.role;

// 1.0.4 Render Interactive Custom Expat Tools
renderCustomExpatTool(focusArea);

// 1.0.5 Vault Quick-Upload Listener & Drag events
const quickDropzone = document.getElementById('overview-quick-upload-dropzone');
const quickFileInput = document.getElementById('overview-quick-upload-input');
const quickStatus = document.getElementById('overview-quick-upload-status');

if (quickDropzone && quickFileInput) {
  quickDropzone.onclick = () => quickFileInput.click();

  quickFileInput.onchange = async (e) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      await handleQuickUpload(files[0]);
    }
  };

  quickDropzone.ondragover = (e) => {
    e.preventDefault();
    quickDropzone.style.background = 'var(--accent-light)';
    quickDropzone.style.borderColor = 'var(--accent)';
  };

  quickDropzone.ondragleave = (e) => {
    e.preventDefault();
    quickDropzone.style.background = 'var(--bg-primary)';
    quickDropzone.style.borderColor = 'var(--border-color)';
  };

  quickDropzone.ondrop = async (e) => {
    e.preventDefault();
    quickDropzone.style.background = 'var(--bg-primary)';
    quickDropzone.style.borderColor = 'var(--border-color)';
    const files = e.dataTransfer.files;
    if (files && files.length > 0) {
      await handleQuickUpload(files[0]);
    }
  };
}

async function handleQuickUpload(file) {
  if (quickStatus) {
    quickStatus.style.display = 'block';
    quickStatus.innerText = `Uploading ${file.name}...`;
  }
  await handleFileUpload(uid, file);
  if (quickStatus) {
    quickStatus.innerText = `✅ Uploaded ${file.name} to Vault!`;
    setTimeout(() => {
      quickStatus.style.display = 'none';
    }, 3000);
  }
}

// 1.0.6 Bookings Panel (Overview Card)
const sessionBox = document.getElementById('overview-session-box');
if (sessionBox) {
  sessionBox.innerHTML = '';
  const upcomingSession = mockBookingsData[focusArea]?.upcoming?.[0];
  if (upcomingSession) {
    sessionBox.innerHTML = `
      <div style="display: flex; align-items: center; gap: 14px; background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 12px; padding: 16px; margin-bottom: 12px;">
        <img src="${upcomingSession.guideAvatar}" style="width: 44px; height: 44px; border-radius: 50%; object-fit: cover;" />
        <div style="flex: 1;">
          <span style="font-size: 0.72rem; font-weight: 700; color: #10b981; text-transform: uppercase; display: block; margin-bottom: 2px;">Confirmed</span>
          <h4 style="font-weight: 700; font-size: 0.88rem; margin: 0; color: var(--text-primary);">${upcomingSession.type}</h4>
          <p style="font-size: 0.78rem; color: var(--text-secondary); margin: 2px 0 6px 0;">with ${upcomingSession.guideName}</p>
          <span style="font-size: 0.8rem; font-weight: 600; color: var(--accent); display: flex; align-items: center; gap: 4px;">
            📅 ${upcomingSession.date} at ${upcomingSession.time}
          </span>
        </div>
      </div>
      <div style="display: flex; gap: 8px;">
        <a href="${upcomingSession.joinLink}" target="_blank" class="btn btn-primary" style="flex: 1; padding: 10px; font-size: 0.78rem; border-radius: 8px; font-weight: 600; text-align: center; text-decoration: none;">📹 Join Session</a>
        <button class="btn btn-outline" id="btn-overview-reschedule" style="flex: 1; padding: 10px; font-size: 0.78rem; border-radius: 8px; font-weight: 600; cursor: pointer;">Reschedule</button>
      </div>
    `;

    const btnResched = document.getElementById('btn-overview-reschedule');
    if (btnResched) {
      btnResched.addEventListener('click', () => {
        alert("To reschedule this coaching session, please send a direct message to your advisor in the Message Center.");
      });
    }
  } else {
    sessionBox.innerHTML = `
      <div style="text-align: center; padding: 20px 10px; border: 1px dashed var(--border-color); border-radius: 12px; background: rgba(0,0,0,0.01);">
        <p style="font-size: 0.85rem; color: var(--text-secondary); margin-bottom: 12px;">You don't have any coaching sessions booked yet.</p>
        <button class="btn btn-primary" id="btn-overview-book-first" style="padding: 10px 18px; font-size: 0.78rem; border-radius: 8px; font-weight: 600; cursor: pointer;">Schedule Your First Session</button>
      </div>
    `;
    const btnBookFirst = document.getElementById('btn-overview-book-first');
    if (btnBookFirst) {
      btnBookFirst.addEventListener('click', () => {
        switchDashboardTab('bookings');
      });
    }
  }
}

// 1.0.7 Bind Overview Action Links
const btnOverChat = document.getElementById('btn-overview-chat');
const btnOverBook = document.getElementById('btn-overview-book');
const linkToRoadmap = document.getElementById('link-to-roadmap-checklist');
if (btnOverChat) {
  btnOverChat.addEventListener('click', () => switchDashboardTab('messages'));
}
if (btnOverBook) {
  btnOverBook.addEventListener('click', () => switchDashboardTab('bookings'));
}
if (linkToRoadmap) {
  linkToRoadmap.addEventListener('click', (e) => {
    e.preventDefault();
    switchDashboardTab('roadmap');
  });
}

