// Helper to Render Custom Interactive Expat Tools on Overview Tab
function renderCustomExpatTool(focusArea) {
  const card = document.getElementById('overview-custom-tool-card');
  if (!card) return;

  if (focusArea === 'Status & Visas') {
    card.innerHTML = `
      <h4 style="font-weight: 600; font-size: 1.1rem; color: var(--text-primary); margin: 0 0 8px 0;">Visa Timeline Estimator</h4>
      <p style="font-size: 0.8rem; color: var(--text-secondary); margin: 0 0 16px 0;">
        Relocating isn't instant. Adjust the slider to see processing stages for different visa classes.
      </p>
      <div style="margin-bottom: 16px;">
        <label style="font-size: 0.8rem; font-weight: 600; color: var(--text-primary); display: block; margin-bottom: 6px;">Select Visa Pathway:</label>
        <select id="tool-visa-type" style="width: 100%; padding: 8px 12px; border: 1px solid var(--border-color); border-radius: 8px; font-size: 0.85rem; background: var(--bg-primary); color: var(--text-primary);">
          <option value="blue_card">EU Blue Card (High Skilled)</option>
          <option value="digital_nomad">Digital Nomad / Remote Work</option>
          <option value="student">Student / Academic Visa</option>
        </select>
      </div>
      <div style="margin-bottom: 20px;">
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem; font-weight: 600; color: var(--text-primary); margin-bottom: 6px;">
          <span>Consular Backlog Queue:</span>
          <span id="tool-visa-delay-val">2 months</span>
        </div>
        <input type="range" id="tool-visa-slider" min="1" max="6" value="2" style="width: 100%; accent-color: var(--accent);" />
      </div>
      <div style="background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 10px; padding: 14px;">
        <h5 style="font-size: 0.82rem; font-weight: 700; text-transform: uppercase; color: var(--text-secondary); margin: 0 0 10px 0; display: flex; justify-content: space-between; align-items: center;">
          Estimated Duration: <span id="tool-visa-total-wks" style="color: var(--accent); font-size: 1rem; font-weight: 700;">12 Weeks</span>
        </h5>
        <div style="display: flex; gap: 4px; height: 6px; background: rgba(0,0,0,0.05); border-radius: 3px; overflow: hidden; margin-bottom: 8px;">
          <div id="bar-prep" style="width: 20%; background: #10b981; height: 100%;"></div>
          <div id="bar-consul" style="width: 30%; background: #f59e0b; height: 100%;"></div>
          <div id="bar-gov" style="width: 50%; background: #3b82f6; height: 100%;"></div>
        </div>
        <div style="display: flex; justify-content: space-between; font-size: 0.72rem; color: var(--text-secondary); line-height: 1.3;">
          <span>🟢 Prep (2 wks)</span>
          <span><span>🟡 Consul: </span><span id="txt-consul-wks">4 wks</span></span>
          <span>🔵 Gov (6 wks)</span>
        </div>
      </div>
    `;

    const typeSelect = document.getElementById('tool-visa-type');
    const delaySlider = document.getElementById('tool-visa-slider');
    const delayVal = document.getElementById('tool-visa-delay-val');
    const totalWks = document.getElementById('tool-visa-total-wks');
    const txtConsulWks = document.getElementById('txt-consul-wks');
    const barPrep = document.getElementById('bar-prep');
    const barConsul = document.getElementById('bar-consul');
    const barGov = document.getElementById('bar-gov');

    const updateTimeline = () => {
      const delay = parseInt(delaySlider.value);
      delayVal.innerText = `${delay} month${delay > 1 ? 's' : ''}`;

      let prepW = 2;
      let consulW = delay * 4;
      let govW = 6;

      if (typeSelect.value === 'digital_nomad') {
        prepW = 3;
        govW = 4;
      } else if (typeSelect.value === 'student') {
        prepW = 1;
        govW = 8;
      }

      const total = prepW + consulW + govW;
      totalWks.innerText = `${total} Weeks`;
      if (txtConsulWks) txtConsulWks.innerText = `${consulW} wks`;

      const totalW = prepW + consulW + govW;
      if (barPrep) barPrep.style.width = `${(prepW / totalW) * 100}%`;
      if (barConsul) barConsul.style.width = `${(consulW / totalW) * 100}%`;
      if (barGov) barGov.style.width = `${(govW / totalW) * 100}%`;
    };

    if (typeSelect) typeSelect.onchange = updateTimeline;
    if (delaySlider) delaySlider.oninput = updateTimeline;
    updateTimeline();

  } else if (focusArea === 'Career & Jobs') {
    card.innerHTML = `
      <h4 style="font-weight: 600; font-size: 1.1rem; color: var(--text-primary); margin: 0 0 8px 0;">Resume Localization Coach</h4>
      <p style="font-size: 0.8rem; color: var(--text-secondary); margin: 0 0 16px 0;">
        Expat application formats vary widely. Select your target country and drop your resume draft to run our compliance audit.
      </p>
      <div style="margin-bottom: 14px;">
        <label style="font-size: 0.8rem; font-weight: 600; color: var(--text-primary); display: block; margin-bottom: 4px;">Target Relocation Country:</label>
        <select id="tool-resume-country" style="width: 100%; padding: 8px 12px; border: 1px solid var(--border-color); border-radius: 8px; font-size: 0.85rem; background: var(--bg-primary); color: var(--text-primary);">
          <option value="DE">Germany (CV Format)</option>
          <option value="UK">United Kingdom (UK Resume)</option>
          <option value="US">United States (ATS Resume)</option>
        </select>
      </div>

      <div id="tool-resume-dropzone" style="border: 2px dashed var(--border-color); border-radius: 12px; padding: 18px; text-align: center; background: var(--bg-primary); cursor: pointer; transition: all 0.2s; margin-bottom: 12px;">
        <div style="font-size: 1.5rem; margin-bottom: 4px;">📄</div>
        <span style="font-size: 0.78rem; font-weight: 600; color: var(--text-primary); display: block;">Drag & drop resume draft</span>
        <span style="font-size: 0.7rem; color: var(--text-secondary);">or click to select file</span>
        <input type="file" id="tool-resume-file-input" style="display: none;" />
      </div>

      <div id="tool-resume-result" style="display: none; background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 10px; padding: 14px;">
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;">
          <span style="font-size: 0.78rem; font-weight: 700; text-transform: uppercase; color: var(--text-secondary);">Localization Match:</span>
          <span id="tool-resume-score" style="color: #10b981; font-weight: 700; font-size: 1rem;">84%</span>
        </div>
        <div style="width: 100%; height: 6px; background: rgba(0,0,0,0.05); border-radius: 3px; overflow: hidden; margin-bottom: 12px;">
          <div id="tool-resume-progress" style="width: 84%; height: 100%; background: #10b981; transition: width 0.4s ease;"></div>
        </div>
        <ul id="tool-resume-tips" style="font-size: 0.74rem; color: var(--text-secondary); padding-left: 16px; margin: 0; line-height: 1.45;">
        </ul>
      </div>
    `;

    const countrySelect = document.getElementById('tool-resume-country');
    const dropzone = document.getElementById('tool-resume-dropzone');
    const fileInput = document.getElementById('tool-resume-file-input');
    const resultBox = document.getElementById('tool-resume-result');
    const scoreLabel = document.getElementById('tool-resume-score');
    const progressBar = document.getElementById('tool-resume-progress');
    const tipsList = document.getElementById('tool-resume-tips');

    if (dropzone && fileInput) {
      dropzone.onclick = () => fileInput.click();
      fileInput.onchange = () => {
        if (fileInput.files.length > 0) {
          simulateResumeScan(fileInput.files[0].name);
        }
      };
    }

    const simulateResumeScan = (fileName) => {
      dropzone.style.pointerEvents = 'none';
      dropzone.innerHTML = `
        <div style="font-size: 1.5rem; margin-bottom: 4px; animation: spin 2s linear infinite;">⏳</div>
        <span style="font-size: 0.78rem; font-weight: 600; color: var(--text-primary); display: block;">Analyzing cv structure...</span>
        <span style="font-size: 0.7rem; color: var(--text-secondary);">${fileName}</span>
      `;

      setTimeout(() => {
        dropzone.style.pointerEvents = 'auto';
        dropzone.innerHTML = `
          <div style="font-size: 1.5rem; margin-bottom: 4px;">✅</div>
          <span style="font-size: 0.78rem; font-weight: 600; color: var(--text-primary); display: block;">Scan complete!</span>
          <span style="font-size: 0.7rem; color: var(--text-secondary);">Click to re-audit file</span>
        `;

        let score = 75;
        let tips = [];

        if (countrySelect.value === 'DE') {
          score = 72;
          tips = [
            "⚠️ German resumes standardly require a professional profile photo. Add one at the top.",
            "⚠️ Include your Date of Birth (Geburtsdatum) and Nationality, which is standard in Germany.",
            "💡 Chronological work experience layout is ideal for German recruiters."
          ];
        } else if (countrySelect.value === 'US') {
          score = 90;
          tips = [
            "✅ Zero photos found — matches US anti-bias laws.",
            "✅ CV does not specify date of birth or marital status.",
            "⚠️ Adjust verbs to focus on quantitative metrics (e.g. 'improved margins by 15%')."
          ];
        } else {
          score = 82;
          tips = [
            "✅ Standard size (A4) template fits UK formats.",
            "⚠️ Change spelling from Americanized to UK English (e.g. 'Optimize' ➔ 'Optimise').",
            "💡 Keep total length strictly under 2 pages."
          ];
        }

        if (resultBox) resultBox.style.display = 'block';
        if (scoreLabel) scoreLabel.innerText = `${score}%`;
        if (progressBar) progressBar.style.width = `${score}%`;
        if (tipsList) {
          tipsList.innerHTML = tips.map(tip => `<li style="margin-bottom: 6px;">${tip}</li>`).join('');
        }
      }, 1500);
    };

  } else {
    card.innerHTML = `
      <h4 style="font-weight: 600; font-size: 1.1rem; color: var(--text-primary); margin: 0 0 8px 0;">Salary Gross-to-Net Estimator</h4>
      <p style="font-size: 0.8rem; color: var(--text-secondary); margin: 0 0 16px 0;">
        Gross salaries can be deceptive due to different progressive tax brackets. Adjust the slider to see local take-home.
      </p>
      <div style="margin-bottom: 16px;">
        <div style="display: flex; justify-content: space-between; font-size: 0.82rem; font-weight: 600; color: var(--text-primary); margin-bottom: 6px;">
          <span>Gross Annual Salary:</span>
          <span id="tool-fin-salary-txt" style="color: var(--accent); font-weight: 700;">$75,000</span>
        </div>
        <input type="range" id="tool-fin-salary-slider" min="40000" max="150000" step="5000" value="75000" style="width: 100%; accent-color: var(--accent);" />
      </div>

      <div style="background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 10px; padding: 14px; display: flex; flex-direction: column; gap: 10px;">
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem;">
          <span style="color: var(--text-secondary);">Estimated Income Tax (Avg):</span>
          <span id="tool-fin-tax" style="font-weight: 600; color: var(--text-primary);">-28%</span>
        </div>
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem;">
          <span style="color: var(--text-secondary);">Social Security & Health:</span>
          <span id="tool-fin-soc" style="font-weight: 600; color: var(--text-primary);">-9%</span>
        </div>
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem; border-bottom: 1px solid var(--border-color); padding-bottom: 8px; margin-bottom: 2px;">
          <span style="color: var(--text-secondary);">Typical Rent & Expenses:</span>
          <span id="tool-fin-rent" style="font-weight: 600; color: var(--text-primary);">$1,800/mo</span>
        </div>
        <div style="display: flex; justify-content: space-between; align-items: center;">
          <span style="font-size: 0.8rem; font-weight: 700; color: var(--text-primary);">Net Monthly Take-Home:</span>
          <span id="tool-fin-net-mo" style="color: var(--accent); font-weight: 700; font-size: 1.05rem;">$3,937</span>
        </div>
        <div style="display: flex; justify-content: space-between; align-items: center; background: rgba(16,185,129,0.05); padding: 8px 10px; border-radius: 6px; border: 1px solid rgba(16,185,129,0.15);">
          <span style="font-size: 0.74rem; font-weight: 600; color: #10b981;">Est. Monthly Savings:</span>
          <span id="tool-fin-savings" style="font-weight: 700; color: #10b981; font-size: 0.85rem;">+$2,137</span>
        </div>
      </div>
    `;

    const salarySlider = document.getElementById('tool-fin-salary-slider');
    const salaryTxt = document.getElementById('tool-fin-salary-txt');
    const taxField = document.getElementById('tool-fin-tax');
    const socField = document.getElementById('tool-fin-soc');
    const rentField = document.getElementById('tool-fin-rent');
    const netMoField = document.getElementById('tool-fin-net-mo');
    const savingsField = document.getElementById('tool-fin-savings');

    const updateCalculator = () => {
      const gross = parseInt(salarySlider.value);
      salaryTxt.innerText = `$${gross.toLocaleString()}`;

      let taxRate = 0.20;
      if (gross > 100000) taxRate = 0.35;
      else if (gross > 70000) taxRate = 0.28;
      else if (gross > 50000) taxRate = 0.24;

      const socRate = 0.09;
      const totalDeductions = taxRate + socRate;
      const netAnnual = gross * (1 - totalDeductions);
      const netMonthly = Math.round(netAnnual / 12);

      let rent = 1500;
      if (gross > 120000) rent = 2400;
      else if (gross > 90000) rent = 2000;
      else if (gross > 60000) rent = 1600;

      const estSavings = netMonthly - rent;

      taxField.innerText = `-${Math.round(taxRate * 100)}%`;
      socField.innerText = `-${Math.round(socRate * 100)}%`;
      rentField.innerText = `$${rent.toLocaleString()}/mo`;
      netMoField.innerText = `$${netMonthly.toLocaleString()}`;
      savingsField.innerText = estSavings > 0 
        ? `+$${estSavings.toLocaleString()}` 
        : `$${estSavings.toLocaleString()}`;

      if (estSavings > 0) {
        savingsField.parentElement.style.background = 'rgba(16,185,129,0.05)';
        savingsField.parentElement.style.borderColor = 'rgba(16,185,129,0.15)';
        savingsField.parentElement.style.color = '#10b981';
      } else {
        savingsField.parentElement.style.background = 'rgba(239,68,68,0.05)';
        savingsField.parentElement.style.borderColor = 'rgba(239,68,68,0.15)';
        savingsField.parentElement.style.color = '#ef4444';
      }
    };

    if (salarySlider) salarySlider.oninput = updateCalculator;
    updateCalculator();
  }
}

