    const simulateResumeScan = (fileName) => {
      dropzone.style.pointerEvents = 'none';
      dropzone.innerHTML = `
        <div style="font-size: 1.5rem; margin-bottom: 4px; animation: spin 2s linear infinite;">⏳</div>
        <span style="font-size: 0.78rem; font-weight: 600; color: var(--text-primary); display: block;">Analyzing cv structure...</span>
        <span style="font-size: 0.7rem; color: var(--text-secondary);">${fileName}</span>
      `;

      setTimeout(() => {
        dropzone.style.pointerEvents = 'auto';
        dropzone.innerHTML = `
          <div style="font-size: 1.5rem; margin-bottom: 4px;">✅</div>
          <span style="font-size: 0.78rem; font-weight: 600; color: var(--text-primary); display: block;">Scan complete!</span>
          <span style="font-size: 0.7rem; color: var(--text-secondary);">Click to re-audit file</span>
