          <span style="color: var(--text-secondary);">Estimated Income Tax (Avg):</span>
          <span id="tool-fin-tax" style="font-weight: 600; color: var(--text-primary);">-28%</span>
        </div>
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem;">
          <span style="color: var(--text-secondary);">Social Security & Health:</span>
          <span id="tool-fin-soc" style="font-weight: 600; color: var(--text-primary);">-9%</span>
        </div>
        <div style="display: flex; justify-content: space-between; font-size: 0.8rem; border-bottom: 1px solid var(--border-color); padding-bottom: 8px; margin-bottom: 2px;">
          <span style="color: var(--text-secondary);">Typical Rent & Expenses:</span>
          <span id="tool-fin-rent" style="font-weight: 600; color: var(--text-primary);">$1,800/mo</span>
        </div>
        <div style="display: flex; justify-content: space-between; align-items: center;">
          <span style="font-size: 0.8rem; font-weight: 700; color: var(--text-primary);">Net Monthly Take-Home:</span>
          <span id="tool-fin-net-mo" style="color: var(--accent); font-weight: 700; font-size: 1.05rem;">$3,937</span>
        </div>
        <div style="display: flex; justify-content: space-between; align-items: center; background: rgba(16,185,129,0.05); padding: 8px 10px; border-radius: 6px; border: 1px solid rgba(16,185,129,0.15);">
          <span style="font-size: 0.74rem; font-weight: 600; color: #10b981;">Est. Monthly Savings:</span>
          <span id="tool-fin-savings" style="font-weight: 700; color: #10b981; font-size: 0.85rem;">+$2,137</span>
        </div>
      </div>
    `;

    const salarySlider = document.getElementById('tool-fin-salary-slider');
    const salaryTxt = document.getElementById('tool-fin-salary-txt');
    const taxField = document.getElementById('tool-fin-tax');
    const socField = document.getElementById('tool-fin-soc');
    const rentField = document.getElementById('tool-fin-rent');
    const netMoField = document.getElementById('tool-fin-net-mo');
    const savingsField = document.getElementById('tool-fin-savings');

    const updateCalculator = () => {
      const gross = parseInt(salarySlider.value);
      salaryTxt.innerText = `$${gross.toLocaleString()}`;

      let taxRate = 0.20;
      if (gross > 100000) taxRate = 0.35;
      else if (gross > 70000) taxRate = 0.28;
      else if (gross > 50000) taxRate = 0.24;

      const socRate = 0.09;
      const totalDeductions = taxRate + socRate;
      const netAnnual = gross * (1 - totalDeductions);
      const netMonthly = Math.round(netAnnual / 12);

      let rent = 1500;
      if (gross > 120000) rent = 2400;
      else if (gross > 90000) rent = 2000;
      else if (gross > 60000) rent = 1600;

      const estSavings = netMonthly - rent;

      taxField.innerText = `-${Math.round(taxRate * 100)}%`;
      socField.innerText = `-${Math.round(socRate * 100)}%`;
      rentField.innerText = `$${rent.toLocaleString()}/mo`;
      netMoField.innerText = `$${netMonthly.toLocaleString()}`;
      savingsField.innerText = estSavings > 0 
        ? `+$${estSavings.toLocaleString()}` 
        : `$${estSavings.toLocaleString()}`;

      if (estSavings > 0) {
        savingsField.parentElement.style.background = 'rgba(16,185,129,0.05)';
        savingsField.parentElement.style.borderColor = 'rgba(16,185,129,0.15)';
        savingsField.parentElement.style.color = '#10b981';
      } else {
        savingsField.parentElement.style.background = 'rgba(239,68,68,0.05)';
        savingsField.parentElement.style.borderColor = 'rgba(239,68,68,0.15)';
        savingsField.parentElement.style.color = '#ef4444';
      }
    };

    if (salarySlider) salarySlider.oninput = updateCalculator;
    updateCalculator();
  }
}

