  'Immigration Status': 'Status & Visas',
  'Tech Career Advancement': 'Career & Jobs',
  'First-Time Homebuyer': 'Finance & Credit'
};

const AppStateStore = {
  _state: {
    currentPhase: 'Immigration Status'
  },
  _listeners: [],
  getState() {
    return this._state;
  },
  setState(newState) {
    this._state = { ...this._state, ...newState };
    // Keep portalActiveFocusArea synchronized
    if (newState.currentPhase) {
      portalActiveFocusArea = phaseToFocusArea[newState.currentPhase];
    }
    this._notify();
  },
  subscribe(listener) {
    this._listeners.push(listener);
    // Return unsubscribe function
    return () => {
      this._listeners = this._listeners.filter(l => l !== listener);
    };
  },
  _notify() {
    this._listeners.forEach(l => l(this._state));
  }
};

