// Phase 5 Action Roadmap Priorities Selector
function getTop3Priorities(checklistItems, focusArea, advisorName) {
  const tasks = checklistItems.map(item => {
    return typeof item === 'object' ? { ...item } : { label: item, val: item };
  });

  // Create a dynamic peer-interaction task based on focus area
  let peerTask = {};
  if (focusArea === 'Status & Visas') {
    peerTask = {
      label: `Review visa application readiness and pathway options with ${advisorName}`,
      val: "peer_review_visa"
    };
  } else if (focusArea === 'Career & Jobs') {
    peerTask = {
      label: `Do a mock interview and resume review session with ${advisorName}`,
      val: "peer_review_resume"
    };
  } else {
    peerTask = {
      label: `Discuss local credit building tips and tax optimization with ${advisorName}`,
      val: "peer_review_finance"
    };
  }

  // Ensure we take the first 2 tasks and inject our peer task as the 3rd task
  const top3 = tasks.slice(0, 2);
  top3.push(peerTask);
  return top3;
}

