// 1.1.3 Render Breakthroughs chronological log (Phase 6)
const logList = document.getElementById('breakthroughs-log-list');
if (logList) {
  logList.innerHTML = '';
  const breakthroughs = data.breakthroughs || [];
  if (breakthroughs.length === 0) {
    logList.innerHTML = `
      <p style="font-size: 0.8rem; color: var(--text-secondary); font-style: italic; text-align: center; margin: 20px 0;">
        No breakthroughs logged yet. Complete a session or log one above to begin your quest history!
      </p>
    `;
  } else {
    // Sort chronologically (descending - newest first)
    const sorted = [...breakthroughs].sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    sorted.forEach(item => {
      const dateStr = new Date(item.timestamp).toLocaleDateString(undefined, { 
        month: 'short', 
        day: 'numeric', 
        year: 'numeric' 
      });
      const block = document.createElement('div');
      block.style.cssText = 'background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 10px; padding: 12px; margin-bottom: 8px; box-shadow: var(--shadow-sm);';
      block.innerHTML = `
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
          <span class="badge" style="background-color: var(--accent-light); color: var(--accent); font-weight: 700; padding: 2px 8px; border-radius: 20px; font-size: 0.68rem;">
            ${item.phase}
          </span>
          <span style="font-size: 0.72rem; color: var(--text-secondary); font-weight: 500;">
            ${dateStr}
          </span>
        </div>
        <p style="font-size: 0.82rem; color: var(--text-primary); line-height: 1.4; margin: 4px 0 6px 0;">
          "${item.takeaway}"
        </p>
        <div style="font-size: 0.74rem; color: var(--text-secondary); display: flex; align-items: center; gap: 4px;">
          <span>Guide:</span>
          <span style="font-weight: 600; color: var(--text-primary);">${item.guideName}</span>
        </div>
      `;
      logList.appendChild(block);
    });
  }
}

// Bind manual takeaway submission button (Phase 6)
const btnAddTakeaway = document.getElementById('btn-add-takeaway');
const takeawayInput = document.getElementById('takeaway-input');
if (btnAddTakeaway && takeawayInput) {
  // Remove old event listeners by cloning button
  const newBtn = btnAddTakeaway.cloneNode(true);
  btnAddTakeaway.parentNode.replaceChild(newBtn, btnAddTakeaway);

  newBtn.addEventListener('click', async () => {
    const text = takeawayInput.value.trim();
    if (!text) return;

    const newBreakthrough = {
      timestamp: new Date().toISOString(),
      phase: AppStateStore.getState().currentPhase,
      guideName: advisor.name,
      takeaway: text
    };

    let updatedBreakthroughs = [...(data.breakthroughs || [])];
    updatedBreakthroughs.push(newBreakthrough);

    try {
      if (db) {
        const userDocRef = doc(db, 'users', uid);
        await setDoc(userDocRef, {
          breakthroughs: updatedBreakthroughs,
          updatedAt: new Date()
        }, { merge: true });
      }
    } catch (err) {
      console.warn("Error saving breakthrough to Firestore:", err);
    }

    // Save to local storage
    let localUsers = JSON.parse(localStorage.getItem('bridge_users') || '{}');
    if (localUsers[uid]) {
      localUsers[uid].breakthroughs = updatedBreakthroughs;
    } else {
      localUsers[uid] = { breakthroughs: updatedBreakthroughs };
    }
    localStorage.setItem('bridge_users', JSON.stringify(localUsers));

    takeawayInput.value = '';
    renderClientDashboard();
  });
}

let checklistItems = getChecklistItems(focusArea, bottleneck);
const savedGoals = quizResults.selectedGoals || [];

// Load homework items
const homeworkItems = data.homework || [];
const homeworkChecklistItems = homeworkItems.map(item => ({
  label: `[Homework] ${item.text}`,
  val: item.id,
  isHomework: true,
  completed: item.completed
}));

// Combined checklist for progress calculation
const combinedChecklistItems = [
  ...checklistItems.map(item => typeof item === 'object' ? { ...item } : { label: item, val: item }),
  ...homeworkChecklistItems
];

const totalCount = combinedChecklistItems.length;
let checkedCount = 0;
combinedChecklistItems.forEach(item => {
  if (item.isHomework) {
    if (item.completed) checkedCount++;
  } else {
    if (savedGoals.includes(item.val)) checkedCount++;
  }
});
const pct = totalCount > 0 ? Math.round((checkedCount / totalCount) * 100) : 0;

// Update Roadmap checklist progress indicators
const progressBadge = document.getElementById('roadmap-progress-badge');
const progressBar = document.getElementById('roadmap-progress-bar');
if (progressBadge) progressBadge.innerText = `${pct}% Completed`;
if (progressBar) progressBar.style.width = `${pct}%`;

// Helper to handle goal updates
const updateGoalSelection = async (goalVal, isChecked) => {
  let updatedSelectedGoals = [...savedGoals];
  if (isChecked) {
    if (!updatedSelectedGoals.includes(goalVal)) {
      updatedSelectedGoals.push(goalVal);
    }
  } else {
    updatedSelectedGoals = updatedSelectedGoals.filter(g => g !== goalVal);
  }

  try {
    if (db) {
      const userDocRef = doc(db, 'users', uid);
      await setDoc(userDocRef, {
        quizResults: {
          ...quizResults,
          selectedGoals: updatedSelectedGoals
        },
        updatedAt: new Date()
      }, { merge: true });
    }
  } catch (err) {
    console.warn("Error saving goal state:", err);
  }

  saveGoalToLocal(uid, quizResults, updatedSelectedGoals);
  renderClientDashboard();
};

// Helper to handle homework updates
const updateHomeworkSelection = async (homeworkId, isChecked) => {
  let updatedHomework = homeworkItems.map(item => {
    if (item.id === homeworkId) {
      return { ...item, completed: isChecked };
    }
    return item;
  });

  try {
    if (db) {
      const userDocRef = doc(db, 'users', uid);
      await setDoc(userDocRef, {
        homework: updatedHomework,
        updatedAt: new Date()
      }, { merge: true });
    }
  } catch (err) {
    console.warn("Error saving homework state:", err);
  }

  // Save to local storage
  let localUsers = JSON.parse(localStorage.getItem('bridge_users') || '{}');
  if (localUsers[uid]) {
    localUsers[uid].homework = updatedHomework;
    localUsers[uid].updatedAt = new Date().toISOString();
    localStorage.setItem('bridge_users', JSON.stringify(localUsers));
  }

  renderClientDashboard();
};

// 1.1.1 Populate Top Priorities (Overview checklist, top 3 items + homework)
const overviewChecklist = document.getElementById('overview-checklist-container');
if (overviewChecklist) {
  overviewChecklist.innerHTML = '';
  const top3Items = getTop3Priorities(checklistItems, focusArea, advisor.name);

  const combinedPriorities = [
    ...top3Items.map(item => typeof item === 'object' ? { ...item } : { label: item, val: item }),
    ...homeworkChecklistItems
  ];

  combinedPriorities.forEach((item) => {
    const text = item.label;
    const val = item.val;
    const checked = item.isHomework ? (item.completed ? 'checked' : '') : (savedGoals.includes(val) ? 'checked' : '');

    const row = document.createElement('label');
    row.style.cssText = 'display: flex; align-items: flex-start; gap: 10px; cursor: pointer; font-size: 0.88rem; line-height: 1.4; color: var(--text-primary); margin-bottom: 6px;';
    row.innerHTML = `
      <input type="checkbox" class="over-goal-checkbox" data-goal="${val}" ${item.isHomework ? 'data-is-homework="true"' : ''} ${checked} style="margin-top: 3px;" />
      <span>${text}</span>
    `;
    overviewChecklist.appendChild(row);
  });

  overviewChecklist.querySelectorAll('.over-goal-checkbox').forEach(box => {
    box.addEventListener('change', () => {
      const goalVal = box.getAttribute('data-goal');
      const isHomework = box.getAttribute('data-is-homework') === 'true';
      if (isHomework) {
        updateHomeworkSelection(goalVal, box.checked);
      } else {
        updateGoalSelection(goalVal, box.checked);
      }
    });
  });
}

// 1.1.2 Populate Action Roadmap Checklist (Full Roadmap tab)
const checklistContainer = document.getElementById('db-checklist-container');
if (checklistContainer) {
