// Helper to retrieve user client data
async function getClientData(clientId) {
  if (mockClientsRegistry[clientId]) {
    return mockClientsRegistry[clientId];
  }

  let data = null;
  if (db) {
    try {
      const userDoc = await getDoc(doc(db, 'users', clientId));
      if (userDoc.exists()) {
        data = userDoc.data();
      }
    } catch (err) {
      console.warn("Firestore getDoc in getClientData failed:", err);
    }
  }

  if (!data) {
    let localUsers = JSON.parse(localStorage.getItem('bridge_users') || '{}');
    data = localUsers[clientId];
  }

  return data;
}

