let activeSelectedClientIdForAdvisor = null;
let sessionAssignedHomework = [];

// Slide-out panel control logic
async function openContextBriefPanel(clientId) {
  activeSelectedClientIdForAdvisor = clientId;
  sessionAssignedHomework = [];

  const panel = document.getElementById('guide-context-brief-panel');
  if (!panel) return;

  const clientData = await getClientData(clientId);
  if (!clientData) return;

  const quizResults = clientData.quizResults || {};
  const scores = quizResults.scores || { status: 0, career: 0, finance: 0 };
  const focusArea = quizResults.focusArea || "Status & Visas";
  const bottleneck = quizResults.biggestBottleneck || "status";
  const displayName = clientData.displayName || clientData.email.split('@')[0];

  // Header updates
  const nameEl = document.getElementById('panel-mentee-name');
  const avatarEl = document.getElementById('panel-mentee-avatar');
  const phaseEl = document.getElementById('panel-mentee-phase');

  if (nameEl) nameEl.innerText = displayName;
  if (avatarEl) {
    avatarEl.innerText = displayName.charAt(0).toUpperCase();
  }
  const clientPhase = focusAreaToPhase[getDisplayFocusArea(focusArea)] || "Immigration Status";
  if (phaseEl) phaseEl.innerText = clientPhase;

  // Context details
  const bottleneckEl = document.getElementById('panel-mentee-bottleneck');
  if (bottleneckEl) {
    bottleneckEl.innerText = bottleneck.charAt(0).toUpperCase() + bottleneck.slice(1);
  }

  const scoresContainer = document.getElementById('panel-mentee-scores');
  if (scoresContainer) {
    const statusPct = (scores.status || 0) * 10;
    const careerPct = (scores.career || 0) * 10;
    const financePct = (scores.finance || 0) * 10;

    scoresContainer.innerHTML = `
      ${renderProgressRing('Status', statusPct)}
      ${renderProgressRing('Career', careerPct)}
      ${renderProgressRing('Finance', financePct)}
    `;

    setTimeout(() => {
      scoresContainer.querySelectorAll('.progress-ring-circle').forEach(circle => {
        const pct = parseFloat(circle.getAttribute('data-pct'));
        const r = 24;
        const circumference = 2 * Math.PI * r;
        const offset = circumference - (pct / 100) * circumference;
        circle.style.strokeDasharray = `${circumference} ${circumference}`;
        circle.style.strokeDashoffset = offset;
      });
    }, 50);
  }

  // Auto-Logged metadata
  const metadataContainer = document.getElementById('panel-log-metadata');
  const activeGuide = mockAdvisorsData[getDisplayFocusArea(focusArea)]?.name || "David K.";
  if (metadataContainer) {
    const now = new Date();
    const dateStr = now.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
    const timeStr = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    metadataContainer.innerHTML = `
      <span>📅 <strong>Date:</strong> ${dateStr}</span>
      <span>⏰ <strong>Time:</strong> ${timeStr}</span>
      <span>👤 <strong>Guide:</strong> ${activeGuide}</span>
      <span>🗺️ <strong>Phase:</strong> ${clientPhase}</span>
    `;
  }

  // Reset Form Fields
  const takeawaysEl = document.getElementById('panel-takeaways');
  const notesEl = document.getElementById('panel-notes-next-guide');
  const charCounter = document.getElementById('takeaways-char-counter');
  const hwTextEl = document.getElementById('panel-hw-text');
  const hwListEl = document.getElementById('panel-hw-list');

  if (takeawaysEl) takeawaysEl.value = '';
  if (notesEl) notesEl.value = '';
  if (charCounter) charCounter.innerText = '0/500';
  if (hwTextEl) hwTextEl.value = '';
  if (hwListEl) hwListEl.innerHTML = '';

  const checkboxes = document.querySelectorAll('input[name="topic-focus"]');
  checkboxes.forEach(cb => cb.checked = false);

  if (takeawaysEl && charCounter) {
    takeawaysEl.oninput = () => {
      const len = takeawaysEl.value.length;
      charCounter.innerText = `${len}/500`;
    };
  }

  // Homework addition handler
  const btnAddHw = document.getElementById('btn-add-hw-item');
  if (btnAddHw && hwTextEl && hwListEl) {
    btnAddHw.onclick = () => {
      const text = hwTextEl.value.trim();
      if (!text) return;

      const hwId = `hw_${Date.now()}_${Math.floor(Math.random() * 1000)}`;
      sessionAssignedHomework.push({
        id: hwId,
        text: text,
        completed: false,
        assignedBy: activeGuide,
        assignedAt: new Date().toISOString()
      });

      hwTextEl.value = '';
      renderSessionHomeworkList();
    };
  }

  function renderSessionHomeworkList() {
    if (!hwListEl) return;
    hwListEl.innerHTML = '';
    sessionAssignedHomework.forEach((item, index) => {
      const row = document.createElement('div');
      row.style.cssText = 'display: flex; align-items: center; justify-content: space-between; background: var(--bg-primary); border: 1px solid var(--border-color); padding: 8px 12px; border-radius: 8px; font-size: 0.8rem; margin-top: 4px; box-sizing: border-box;';
      row.innerHTML = `
        <span style="color: var(--text-primary);">📝 ${item.text}</span>
        <button type="button" class="btn-remove-hw" data-index="${index}" style="background: none; border: none; color: #b91c1c; cursor: pointer; font-size: 1.1rem; font-weight: bold; line-height: 1; padding: 0 4px;">&times;</button>
      `;
      row.querySelector('.btn-remove-hw').onclick = () => {
        sessionAssignedHomework.splice(index, 1);
        renderSessionHomeworkList();
      };
      hwListEl.appendChild(row);
    });
  }

  loadContinuityHistory(clientId, clientData);
  panel.style.right = '0';
}

// Load and display case logs chronologically
async function loadContinuityHistory(clientId, clientData) {
  const historyContainer = document.getElementById('panel-log-history');
  if (!historyContainer) return;
  historyContainer.innerHTML = '<p style="font-size: 0.8rem; color: var(--text-secondary); font-style: italic; text-align: center; padding: 10px;">Loading history log...</p>';

  let logs = [];
  if (db) {
    try {
      const logsCol = collection(db, 'users', clientId, 'continuity_logs');
      const logsQuery = query(logsCol, orderBy('timestamp', 'desc'));
      const querySnap = await getDocs(logsQuery);
      querySnap.forEach(docSnap => {
        logs.push(docSnap.data());
      });
    } catch (err) {
      console.warn("Firestore continuity history read failed, checking localStorage fallback:", err);
    }
  }

  if (logs.length === 0) {
    logs = JSON.parse(localStorage.getItem(`bridge_continuity_logs_${clientId}`) || '[]');
    logs.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
  }

  if (logs.length === 0) {
    // Add one default historical log for mock users to look premium
    if (clientId.startsWith('mock-')) {
      const mockAdvisor = mockAdvisorsData[getDisplayFocusArea(clientData.quizResults.focusArea)] || { name: "David K." };
      const mockLog = {
        timestamp: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString(),
        guideName: mockAdvisor.name,
        phase: focusAreaToPhase[getDisplayFocusArea(clientData.quizResults.focusArea)] || "Immigration Status",
        topics: ["Visa Options", "Interview Prep"],
        takeaway: "Reviewed scorecard checklist and established timeline roadmap. Discussed credentials evaluation and translation pathways.",
        notesNextGuide: "Candidate has strong qualifications. Advised focused efforts on talent visa pathway options.",
        homework: clientData.homework || []
      };
      logs.push(mockLog);
      localStorage.setItem(`bridge_continuity_logs_${clientId}`, JSON.stringify(logs));
    } else {
      historyContainer.innerHTML = `
        <p style="font-size: 0.8rem; color: var(--text-secondary); font-style: italic; text-align: center; padding: 12px; border: 1px dashed var(--border-color); border-radius: 8px;">
          No past logs found. This is their first session with a Guide.
        </p>
      `;
      return;
    }
  }

  historyContainer.innerHTML = '';
  logs.forEach(log => {
    const dateStr = new Date(log.timestamp).toLocaleDateString(undefined, { 
      month: 'short', 
      day: 'numeric', 
      year: 'numeric' 
    });

    let homeworkHTML = '';
    if (log.homework && log.homework.length > 0) {
      homeworkHTML += `<div style="font-size: 0.76rem; font-weight: 700; margin-top: 8px; color: var(--text-primary); border-top: 1px solid var(--border-color); padding-top: 8px;">Assigned Homework:</div>`;
      log.homework.forEach(hw => {
        const currentHw = (clientData.homework || []).find(h => h.id === hw.id || h.text === hw.text);
        const isCompleted = currentHw ? currentHw.completed : false;
        const badgeBg = isCompleted ? 'rgba(16, 185, 129, 0.1)' : 'rgba(245, 158, 11, 0.1)';
        const badgeColor = isCompleted ? '#10b981' : '#f59e0b';
        const badgeText = isCompleted ? 'Completed' : 'Pending';

        homeworkHTML += `
          <div style="display: flex; align-items: center; justify-content: space-between; background: var(--bg-secondary); padding: 6px 10px; border-radius: 6px; margin-top: 6px; font-size: 0.76rem; box-sizing: border-box;">
            <span style="color: var(--text-primary);">• ${hw.text}</span>
            <span class="badge" style="background: ${badgeBg}; color: ${badgeColor}; font-weight: 700; font-size: 0.62rem; padding: 2px 6px; border-radius: 6px; border: none;">${badgeText}</span>
          </div>
        `;
      });
    }

    const logBlock = document.createElement('div');
    logBlock.style.cssText = 'background: var(--bg-primary); border: 1px solid var(--border-color); border-radius: 10px; padding: 14px; margin-bottom: 12px; box-shadow: var(--shadow-sm); box-sizing: border-box;';

    logBlock.innerHTML = `
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px;">
        <span class="badge" style="background-color: var(--accent-light); color: var(--accent); font-weight: 700; padding: 2px 8px; border-radius: 20px; font-size: 0.68rem; border: none;">
          ${log.phase}
        </span>
        <span style="font-size: 0.72rem; color: var(--text-secondary); font-weight: 500;">
          ${dateStr}
        </span>
      </div>
      <div style="font-size: 0.76rem; color: var(--text-secondary); margin-bottom: 8px;">
        <strong>Topics Covered:</strong> ${log.topics && log.topics.length > 0 ? log.topics.join(', ') : 'None'}
      </div>
      <p style="font-size: 0.82rem; color: var(--text-primary); line-height: 1.45; margin: 6px 0; word-wrap: break-word;">
        "${log.takeaway}"
      </p>
      <div style="font-size: 0.78rem; background: var(--bg-secondary); border-radius: 6px; padding: 8px 10px; border-left: 3px solid var(--text-secondary); margin: 10px 0;">
        <strong style="color: var(--text-primary); font-size: 0.74rem;">Note for Next Guide:</strong><br/>
        <span style="font-style: italic; color: var(--text-primary); display: block; margin-top: 2px; word-wrap: break-word;">${log.notesNextGuide}</span>
      </div>
      <div style="font-size: 0.74rem; color: var(--text-secondary); display: flex; flex-direction: column; gap: 4px;">
        <div>Guide: <span style="font-weight: 600; color: var(--text-primary);">${log.guideName}</span></div>
        ${homeworkHTML}
      </div>
    `;
    historyContainer.appendChild(logBlock);
  });
}

// Bind Form Submission
const continuityForm = document.getElementById('session-continuity-form');
if (continuityForm) {
  continuityForm.onsubmit = async (e) => {
    e.preventDefault();

    const clientId = activeSelectedClientIdForAdvisor;
    if (!clientId) return;

    const clientData = await getClientData(clientId);
    if (!clientData) return;

    const focusArea = clientData.quizResults?.focusArea || "Status & Visas";
    const clientPhase = focusAreaToPhase[getDisplayFocusArea(focusArea)] || "Immigration Status";
    const activeGuide = mockAdvisorsData[getDisplayFocusArea(focusArea)]?.name || "David K.";

    const selectedTopics = [];
    document.querySelectorAll('input[name="topic-focus"]:checked').forEach(cb => {
      selectedTopics.push(cb.value);
    });

    const takeawaysVal = document.getElementById('panel-takeaways').value.trim();
    const notesNextGuideVal = document.getElementById('panel-notes-next-guide').value.trim();

    if (!takeawaysVal || !notesNextGuideVal) return;

    const newLog = {
      timestamp: new Date().toISOString(),
      guideName: activeGuide,
      phase: clientPhase,
      topics: selectedTopics,
      takeaway: takeawaysVal,
      notesNextGuide: notesNextGuideVal,
      homework: [...sessionAssignedHomework]
    };

    // Save Log
    if (db) {
      try {
        const logsCol = collection(db, 'users', clientId, 'continuity_logs');
        await addDoc(logsCol, newLog);
      } catch (err) {
        console.warn("Firestore save continuity log failed:", err);
      }
    }

    let localLogs = JSON.parse(localStorage.getItem(`bridge_continuity_logs_${clientId}`) || '[]');
    localLogs.push(newLog);
    localStorage.setItem(`bridge_continuity_logs_${clientId}`, JSON.stringify(localLogs));

    // Append assigned homework to main client record
    if (sessionAssignedHomework.length > 0) {
      let updatedHomework = [...(clientData.homework || []), ...sessionAssignedHomework];

      if (db) {
        try {
