function isSessionCompleted(dateStr, timeStr) {
  try {
    // Extract end time from format like "10:00 AM - 11:00 AM (EST)"
    const parts = timeStr.split('-');
    if (parts.length < 2) return false;

    // Get end time portion: "11:00 AM (EST)" -> "11:00 AM"
    let endTimePart = parts[1].trim();
    // Strip any timezone label in parentheses: "(EST)", "(CST)", etc.
    endTimePart = endTimePart.replace(/\s*\([^)]*\)\s*/g, '').trim();

    // Combine date + end time: "June 28, 2026 11:00 AM"
    const endDateTimeStr = `${dateStr} ${endTimePart}`;
    const endDate = new Date(endDateTimeStr);

    if (isNaN(endDate.getTime())) {
      console.warn("isSessionCompleted: Invalid date parsed from:", endDateTimeStr);
      return false;
    }

    const now = new Date();

    // STRICT: The session is only "completed" if the current system time
    // is AFTER the scheduled session end time. Future sessions return false.
    return now > endDate;
  } catch (e) {
    console.error("Error in isSessionCompleted:", e);
    return false;
  }
}

