async function startMatchRevealFlow() {
  const overlay = document.getElementById('match-reveal-overlay');
  if (!overlay) return;

  // Show overlay covering the screen
  overlay.style.display = 'flex';

  // Initial loading state
  overlay.innerHTML = `<h2 id="loading-text" style="font-family: 'Instrument Serif', serif; font-size: 2.5rem; font-style: italic; color: #112F20; margin: 0;">Analyzing timeline...</h2>`;

  const loadingText = document.getElementById('loading-text');

  // Loading Animation
  setTimeout(() => {
    const el = document.getElementById('loading-text');
    if (el) el.innerText = "Identifying core bottlenecks...";
  }, 600);

  setTimeout(() => {
    const el = document.getElementById('loading-text');
    if (el) el.innerText = "Curating guide network...";
  }, 1200);

  // After 2000ms, reveal the selection layout
  setTimeout(async () => {
    // 1. Get client data to determine biggest bottleneck
    let bottleneck = 'status';
    if (auth && auth.currentUser) {
      const uid = auth.currentUser.uid;
      let data = null;
      if (db) {
        try {
          const userDocRef = doc(db, 'users', uid);
          const userDoc = await getDoc(userDocRef);
          if (userDoc.exists()) {
            data = userDoc.data();
          }
        } catch (e) {
          console.warn("Firestore lookup failed in reveal:", e);
        }
      }
      if (!data) {
        let localUsers = JSON.parse(localStorage.getItem('bridge_users') || '{}');
        data = localUsers[uid];
      }

      if (data && data.quizResults) {
        bottleneck = data.quizResults.biggestBottleneck || 'status';
      }
    }

    // Map bottleneck to display title
    const bottleneckTitles = {
      'status': 'Immigration Status',
      'career': 'Tech Career Advancement',
      'finance': 'First-Time Homebuyer'
    };
    const displayBottleneck = bottleneckTitles[bottleneck] || 'Immigration Status';

    // Get peer & advisor from registry
    const matchPair = guidesRegistry[bottleneck] || guidesRegistry['status'];
    const peer = matchPair.peer;
    const advisor = matchPair.advisor;

    // Inject HTML directly into the overlay
    overlay.innerHTML = `
      <div class="container" style="max-width: 1000px; margin: 0 auto; text-align: center; display: flex; flex-direction: column; align-items: center; gap: 40px; box-sizing: border-box; font-family: 'Instrument Serif', serif;">
        <h1 style="font-family: 'Instrument Serif', serif; font-size: 3rem; font-style: italic; font-weight: 700; color: #112F20; line-height: 1.2; margin: 0; max-width: 850px;">
          Your current bottleneck is ${displayBottleneck}. We've built your custom roadmap to clear it.
        </h1>

        <div style="display: grid; grid-template-columns: repeat(2, 1fr); gap: 32px; width: 100%; max-width: 900px; margin: 0 auto; text-align: left; font-family: 'Inter', sans-serif;">

          <!-- Card A (Peer Guide) -->
          <div style="display: flex; flex-direction: column; justify-content: space-between; padding: 28px; border: 1px solid var(--border-color); border-radius: 16px; background: var(--bg-secondary); min-height: 220px; box-shadow: var(--shadow-sm); box-sizing: border-box;">
            <div>
              <span class="badge" style="background: var(--accent-light); color: var(--accent); font-weight: 700; font-size: 0.72rem; padding: 4px 10px; border-radius: 20px; text-transform: uppercase; letter-spacing: 0.05em; display: inline-block;">Peer Guide</span>
              <h3 style="font-size: 1.3rem; font-weight: 700; margin: 16px 0 8px 0; color: var(--text-primary);">${peer.name}</h3>
              <p style="font-size: 0.88rem; color: var(--text-secondary); margin: 0; line-height: 1.5; font-weight: 500;">
                Relocated from Nigeria • Cleared the Career Bottleneck in 2024
              </p>
            </div>
            <button class="choose-guide-btn btn btn-primary" data-guide-id="${peer.id}" style="width: 100%; padding: 14px; font-size: 0.9rem; border-radius: 8px; font-weight: 700; cursor: pointer; border: none; margin-top: 24px; display: inline-flex; align-items: center; justify-content: center; color: #FFFFFF;">
              Choose ${peer.name}
            </button>
          </div>

          <!-- Card B (Verified Advisor) -->
          <div style="display: flex; flex-direction: column; justify-content: space-between; padding: 28px; border: 1px solid var(--border-color); border-radius: 16px; background: var(--bg-secondary); min-height: 220px; box-shadow: var(--shadow-sm); box-sizing: border-box;">
            <div>
              <span class="badge" style="background: var(--accent-light); color: var(--accent); font-weight: 700; font-size: 0.72rem; padding: 4px 10px; border-radius: 20px; text-transform: uppercase; letter-spacing: 0.05em; display: inline-block;">Verified Advisor</span>
              <h3 style="font-size: 1.3rem; font-weight: 700; margin: 16px 0 8px 0; color: var(--text-primary);">${advisor.name}</h3>
              <p style="font-size: 0.88rem; color: var(--text-secondary); margin: 0; line-height: 1.5; font-weight: 500;">
                Career Consultant • Helped 150+ users clear Career Bottlenecks
              </p>
            </div>
            <button class="choose-guide-btn btn btn-primary" data-guide-id="${advisor.id}" style="width: 100%; padding: 14px; font-size: 0.9rem; border-radius: 8px; font-weight: 700; cursor: pointer; border: none; margin-top: 24px; display: inline-flex; align-items: center; justify-content: center; color: #FFFFFF;">
              Choose ${advisor.name}
            </button>
          </div>

        </div>

        <div style="margin-top: 20px; font-family: 'Inter', sans-serif;">
          <a id="skip-match-link" href="#" style="font-size: 0.95rem; color: var(--text-secondary); text-decoration: none; font-weight: 600; cursor: pointer; border-bottom: 1px dashed var(--text-secondary);">
            Skip for now
          </a>
        </div>
      </div>
    `;

    // Attach event listeners
    overlay.querySelectorAll('.choose-guide-btn').forEach(btn => {
      btn.addEventListener('click', async () => {
        const id = btn.getAttribute('data-guide-id');
        await saveSelectedGuideAndHandoff(id);
        overlay.style.display = 'none';
      });
    });

    const skipMatchLink = document.getElementById('skip-match-link');
    if (skipMatchLink) {
      skipMatchLink.addEventListener('click', async (e) => {
        e.preventDefault();
        await saveSelectedGuideAndHandoff('unassigned');
        overlay.style.display = 'none';
      });
    }
  }, 2000);
}

